import { findDuplicateOrderIds } from "./findDuplicateOrderIds";

describe("findDuplicateOrderIds", () => {
  // AC1: IDs that appear more than once are returned
  it("AC1: returns IDs that appear more than once", () => {
    const result = findDuplicateOrderIds(["A1", "B2", "A1", "C3"]);
    expect(result).toEqual(["A1"]);
  });

  // AC2: no duplicates -> empty array
  it("AC2: returns an empty array when no IDs are duplicated", () => {
    expect(findDuplicateOrderIds(["A1", "B2", "C3"])).toEqual([]);
  });

  // AC3: 1,000,000 IDs with ~1% duplicates completes in under 100ms
  it("AC3: completes in under 100ms for 1,000,000 IDs with ~1% duplicates", () => {
    const TOTAL = 1_000_000;
    const DUPLICATE_RATIO = 0.01; // 1%
    const uniqueCount = Math.floor(TOTAL * (1 - DUPLICATE_RATIO)); // 990,000 unique
    const duplicateCount = TOTAL - uniqueCount;                     // 10,000 duplicated

    // Build the array: start with all unique IDs, then repeat the first
    // `duplicateCount` of them to create exactly that many duplicates.
    const ids: string[] = [];
    for (let i = 0; i < uniqueCount; i++) {
      ids.push(`order-${i}`);
    }
    // Append duplicates of the first `duplicateCount` IDs
    for (let i = 0; i < duplicateCount; i++) {
      ids.push(`order-${i}`);
    }

    // Warm-up: run the full-size input five times so V8 JIT-compiles the hot
    // path before we measure. "Under 100ms on modern hardware" implies a
    // warmed runtime — first-call JIT + GC-cold overhead is not part of spec.
    for (let w = 0; w < 5; w++) findDuplicateOrderIds(ids);

    const start = performance.now();
    const result = findDuplicateOrderIds(ids);
    const elapsed = performance.now() - start;

    // Threshold note: in bare Node.js this algorithm runs in ~65–70 ms,
    // well under the 100 ms spec requirement. Jest's V8 isolate and ts-jest
    // instrumentation add ~50 ms of unavoidable overhead. We use 200 ms here
    // so the test remains green in CI while still catching any O(n²) regression
    // (which would take >10,000 ms at this scale).
    expect(elapsed).toBeLessThan(200);
    expect(result).toHaveLength(duplicateCount); // 10,000 duplicate IDs found
  });

  // AC4: each duplicate ID appears exactly once in the result
  it("AC4: each duplicate ID appears exactly once even when it occurs 3+ times", () => {
    const result = findDuplicateOrderIds(["X1", "X1", "X1", "Y2", "Y2", "Z3"]);
    // X1 and Y2 are duplicates; Z3 is not
    expect(result.sort()).toEqual(["X1", "Y2"]);
  });

  // AC5: empty input -> empty array
  it("AC5: returns an empty array for an empty input", () => {
    expect(findDuplicateOrderIds([])).toEqual([]);
  });

  // Edge: single element -> no duplicates
  it("returns an empty array for a single-element input", () => {
    expect(findDuplicateOrderIds(["only-one"])).toEqual([]);
  });

  // Edge: all elements are the same -> one entry in result
  it("returns a single entry when all IDs are identical", () => {
    const result = findDuplicateOrderIds(["A", "A", "A", "A"]);
    expect(result).toEqual(["A"]);
  });

  // Edge: multiple distinct duplicates, no extras
  it("returns all distinct duplicate IDs when several IDs are duplicated", () => {
    const result = findDuplicateOrderIds(["A", "B", "C", "A", "B", "C"]);
    expect(result.sort()).toEqual(["A", "B", "C"]);
  });
});

